import{_ as a,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Inicialização: Configuração Inicial do Projeto | opencode-supermemory","description":"Aprenda a usar /supermemory-init para varredura do código, extração de arquitetura e armazenamento na memória persistente entre sessões.","frontmatter":{"title":"Inicialização: Configuração Inicial do Projeto | opencode-supermemory","sidebarTitle":"Inicialização","subtitle":"Inicialização do Projeto: Criando a Primeira Impressão","description":"Aprenda a usar /supermemory-init para varredura do código, extração de arquitetura e armazenamento na memória persistente entre sessões.","tags":["Inicialização","Geração de Memória","Fluxo de Trabalho"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"pt/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"pt/supermemoryai/opencode-supermemory/start/initialization/index.md"}'),r={name:"pt/supermemoryai/opencode-supermemory/start/initialization/index.md"};function s(n,e,d,c,l,p){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="inicializacao-do-projeto-criando-a-primeira-impressao" tabindex="-1">Inicialização do Projeto: Criando a Primeira Impressão <a class="header-anchor" href="#inicializacao-do-projeto-criando-a-primeira-impressao" aria-label="Permalink to &quot;Inicialização do Projeto: Criando a Primeira Impressão&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O Que Você Poderá Fazer Após Concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O Que Você Poderá Fazer Após Concluir&quot;">​</a></h2><ul><li><strong>Familiarizar-se com o projeto em um clique</strong>: Permita que o Agent explore e compreenda todo o código como um novo funcionário.</li><li><strong>Estabelecer memória de longo prazo</strong>: Extraia automaticamente a stack tecnológica, padrões de arquitetura e convenções de código do projeto, armazenando-os no Supermemory.</li><li><strong>Eliminar explicações repetidas</strong>: Nunca mais precise repetir &quot;usamos Bun&quot; ou &quot;todos os componentes devem ter testes&quot; no início de cada sessão.</li></ul><h2 id="o-seu-problema-atual" tabindex="-1">O Seu Problema Atual <a class="header-anchor" href="#o-seu-problema-atual" aria-label="Permalink to &quot;O Seu Problema Atual&quot;">​</a></h2><p>Você já enfrentou estas situações:</p><ul><li><strong>Trabalho repetitivo</strong>: Cada nova sessão exige que você gaste muito tempo explicando as informações básicas do projeto ao Agent.</li><li><strong>Esquecimento de contexto</strong>: O Agent frequentemente esquece a estrutura de diretórios específica do projeto e cria arquivos no lugar errado.</li><li><strong>Inconsistência de padrões</strong>: O código gerado pelo Agent oscila em estilo, às vezes usando <code>interface</code>, outras vezes <code>type</code>.</li></ul><h2 id="quando-usar-esta-tecnica" tabindex="-1">Quando Usar Esta Técnica <a class="header-anchor" href="#quando-usar-esta-tecnica" aria-label="Permalink to &quot;Quando Usar Esta Técnica&quot;">​</a></h2><ul><li><strong>Após instalar o plugin</strong>: Este é o primeiro passo ao usar opencode-supermemory.</li><li><strong>Ao assumir um novo projeto</strong>: Construa rapidamente a base de memória desse projeto.</li><li><strong>Após refatorações importantes</strong>: Quando a arquitetura do projeto mudar e você precisar atualizar o conhecimento do Agent.</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação Antes de Começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação Antes de Começar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Verificação Prévia</p><p>Certifique-se de que você completou as etapas de instalação e configuração em <a href="./../getting-started/">Início Rápido</a> e que o <code>SUPERMEMORY_API_KEY</code> está configurado corretamente.</p></div><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p>O comando <code>/supermemory-init</code> não é essencialmente um programa binário, mas sim um <strong>Prompt cuidadosamente projetado</strong>.</p><p>Quando você executa este comando, ele envia um &quot;guia de onboarding&quot; detalhado ao Agent, instruindo-o a:</p><ol><li><strong>Investigação profunda</strong>: Ler ativamente <code>README.md</code>, <code>package.json</code>, histórico de commits do Git, etc.</li><li><strong>Análise estruturada</strong>: Identificar a stack tecnológica, padrões de arquitetura e convenções implícitas do projeto.</li><li><strong>Armazenamento persistente</strong>: Usar a ferramenta <code>supermemory</code> para armazenar essas percepções no banco de dados na nuvem.</li></ol><div class="info custom-block"><p class="custom-block-title">Escopo da Memória</p><p>O processo de inicialização distingue dois tipos de memória:</p><ul><li><strong>Project Scope</strong>: Aplicável apenas ao projeto atual (ex: comandos de build, estrutura de diretórios).</li><li><strong>User Scope</strong>: Aplicável a todos os seus projetos (ex: seu estilo de código preferido).</li></ul></div><h2 id="siga-junto" tabindex="-1">Siga Junto <a class="header-anchor" href="#siga-junto" aria-label="Permalink to &quot;Siga Junto&quot;">​</a></h2><h3 id="passo-1-executar-o-comando-de-inicializacao" tabindex="-1">Passo 1: Executar o Comando de Inicialização <a class="header-anchor" href="#passo-1-executar-o-comando-de-inicializacao" aria-label="Permalink to &quot;Passo 1: Executar o Comando de Inicialização&quot;">​</a></h3><p>Na caixa de entrada do OpenCode, digite o seguinte comando e envie:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>Por que</strong> Isso carrega o Prompt predefinido e inicia o modo de exploração do Agent.</p><p><strong>O que você deve ver</strong> O Agent começa a responder, indicando que entendeu a tarefa e começou a planejar as etapas de investigação. Ele pode dizer: &quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="passo-2-observar-o-processo-de-exploracao-do-agent" tabindex="-1">Passo 2: Observar o Processo de Exploração do Agent <a class="header-anchor" href="#passo-2-observar-o-processo-de-exploracao-do-agent" aria-label="Permalink to &quot;Passo 2: Observar o Processo de Exploração do Agent&quot;">​</a></h3><p>O Agent executará automaticamente uma série de operações, você só precisa assistir. Geralmente, ele:</p><ol><li><strong>Lê arquivos de configuração</strong>: Lê <code>package.json</code>, <code>tsconfig.json</code>, etc., para entender a stack tecnológica.</li><li><strong>Verifica o histórico do Git</strong>: Executa <code>git log</code> para entender as convenções de commit e contribuidores ativos.</li><li><strong>Explora a estrutura de diretórios</strong>: Usa <code>ls</code> ou <code>list_files</code> para ver o layout do projeto.</li></ol><p><strong>Exemplo de saída</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Aviso de Consumo</p><p>Este processo é uma investigação profunda e pode consumir muitos Tokens (geralmente fará 50+ chamadas de ferramentas). Por favor, aguarde pacientemente até que o Agent reporte a conclusão.</p></div><h3 id="passo-3-verificar-as-memorias-geradas" tabindex="-1">Passo 3: Verificar as Memórias Geradas <a class="header-anchor" href="#passo-3-verificar-as-memorias-geradas" aria-label="Permalink to &quot;Passo 3: Verificar as Memórias Geradas&quot;">​</a></h3><p>Quando o Agent indicar que a inicialização foi concluída, você pode verificar o que ele realmente se lembrou. Digite:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Listar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memórias</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> projeto</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> atual</span></span></code></pre></div><p>Ou chame a ferramenta diretamente (se quiser ver os dados brutos):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>O que você deve ver</strong> O Agent lista uma série de memórias estruturadas, por exemplo:</p><table tabindex="0"><thead><tr><th>Tipo</th><th>Exemplo de Conteúdo</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="passo-4-complementar-omissoes-opcional" tabindex="-1">Passo 4: Complementar Omissões (Opcional) <a class="header-anchor" href="#passo-4-complementar-omissoes-opcional" aria-label="Permalink to &quot;Passo 4: Complementar Omissões (Opcional)&quot;">​</a></h3><p>Se o Agent perdeu algumas informações-chave (como uma regra especial que é apenas verbal), você pode complementar manualmente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Por favor, lembre-se: neste projeto, todo o processamento de datas deve usar a biblioteca dayjs, o uso de Date nativo é proibido.</span></span></code></pre></div><p><strong>O que você deve ver</strong> O Agent responde confirmando e chama <code>supermemory(mode: &quot;add&quot;)</code> para salvar esta nova regra.</p><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de Verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de Verificação ✅&quot;">​</a></h2><ul><li>[ ] Após executar <code>/supermemory-init</code>, o Agent executou automaticamente a tarefa de exploração?</li><li>[ ] O comando <code>list</code> permite visualizar as memórias recém-geradas?</li><li>[ ] O conteúdo das memórias reflete com precisão a situação real do projeto atual?</li></ul><h2 id="aviso-de-armadilhas" tabindex="-1">Aviso de Armadilhas <a class="header-anchor" href="#aviso-de-armadilhas" aria-label="Permalink to &quot;Aviso de Armadilhas&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Não execute com frequência</p><p>A inicialização é um processo demorado que consome muitos Tokens. Geralmente, cada projeto precisa ser executado apenas uma vez. Só execute novamente quando o projeto sofrer mudanças drásticas.</p></div><div class="danger custom-block"><p class="custom-block-title">Aviso de Privacidade</p><p>Embora o plugin anonimize automaticamente o conteúdo dentro de tags <code>&lt;private&gt;</code>, durante o processo de inicialização, o Agent lerá muitos arquivos. Certifique-se de que seu repositório não possui chaves sensíveis codificadas (como AWS Secret Key), caso contrário, elas podem ser armazenadas na memória como &quot;configuração do projeto&quot;.</p></div><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>Com <code>/supermemory-init</code>, completamos a transição de &quot;estranho&quot; para &quot;experiente&quot;. Agora, o Agent já se lembrou da arquitetura central e dos padrões do projeto, e nas próximas tarefas de codificação, ele usará automaticamente esse contexto para fornecer assistência mais precisa.</p><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos sobre o <strong><a href="./../../core/context-injection/">Mecanismo de Injeção Automática de Contexto</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como o Agent &quot;se lembra&quot; dessas memórias no início da sessão.</li><li>Como acionar a recuperação de memórias específicas por palavras-chave.</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Definição do Prompt de Inicialização</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>Implementação da Ferramenta de Memória</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>Constantes principais</strong>:</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>: Define o conteúdo específico do Prompt do comando <code>/supermemory-init</code>, orientando o Agent sobre como realizar a investigação e memorização.</li></ul></details>`,50)])])}const g=a(r,[["render",s]]);export{m as __pageData,g as default};
